SELECT release_code,module_version,execution_mode,external_actions_enabled,metadata->>'currentPhase' AS current_phase FROM public.revenue_os_installations WHERE installation_key='revenue-command-os';
SELECT count(*) AS mega_production_tables FROM information_schema.tables WHERE table_schema='public' AND table_name IN ('revenue_os_strategy_outcomes','revenue_os_command_performance','revenue_os_segment_response_models','revenue_os_experiments','revenue_os_experiment_variants','revenue_os_experiment_assignments','revenue_os_experiment_outcomes','revenue_os_control_groups','revenue_os_attribution_events','revenue_os_attribution_results','revenue_os_adaptive_schedules','revenue_os_strategy_suppressions','revenue_os_winning_play_scaling','revenue_os_forecast_calibrations','revenue_os_anomalies','revenue_os_outcome_feedback','revenue_os_durable_jobs','revenue_os_worker_registry','revenue_os_worker_leases','revenue_os_distributed_locks','revenue_os_dead_letters','revenue_os_execution_traces','revenue_os_observability_metrics','revenue_os_queue_health_snapshots','revenue_os_registry_entries','revenue_os_evaluation_runs','revenue_os_regression_runs','revenue_os_cost_budgets','revenue_os_cost_usage','revenue_os_confidence_policies','revenue_os_fallback_policies','revenue_os_emergency_stops','revenue_os_disaster_recovery_runs','revenue_os_security_reviews','revenue_os_production_activations','revenue_os_activation_approvals','revenue_os_recovery_runbooks','revenue_os_mega_production_audit_events');
SELECT count(*) AS phase16_permissions FROM public.revenue_os_permission_registry WHERE phase_introduced=16 AND active=true;
SELECT count(*) AS rls_tables FROM pg_class c JOIN pg_namespace n ON n.oid=c.relnamespace WHERE n.nspname='public' AND c.relrowsecurity=true AND c.relname IN ('revenue_os_strategy_outcomes','revenue_os_command_performance','revenue_os_segment_response_models','revenue_os_experiments','revenue_os_experiment_variants','revenue_os_experiment_assignments','revenue_os_experiment_outcomes','revenue_os_control_groups','revenue_os_attribution_events','revenue_os_attribution_results','revenue_os_adaptive_schedules','revenue_os_strategy_suppressions','revenue_os_winning_play_scaling','revenue_os_forecast_calibrations','revenue_os_anomalies','revenue_os_outcome_feedback','revenue_os_durable_jobs','revenue_os_worker_registry','revenue_os_worker_leases','revenue_os_distributed_locks','revenue_os_dead_letters','revenue_os_execution_traces','revenue_os_observability_metrics','revenue_os_queue_health_snapshots','revenue_os_registry_entries','revenue_os_evaluation_runs','revenue_os_regression_runs','revenue_os_cost_budgets','revenue_os_cost_usage','revenue_os_confidence_policies','revenue_os_fallback_policies','revenue_os_emergency_stops','revenue_os_disaster_recovery_runs','revenue_os_security_reviews','revenue_os_production_activations','revenue_os_activation_approvals','revenue_os_recovery_runbooks','revenue_os_mega_production_audit_events');
DO $$ BEGIN IF EXISTS(SELECT 1 FROM public.revenue_os_installations WHERE installation_key='revenue-command-os' AND external_actions_enabled=true) THEN RAISE EXCEPTION 'External actions must remain governed after MZ16 install';END IF;END $$;
